section.programlisting:
1 #ifndef HDEF_ANIMATIONDATA
2 #define HDEF_ANIMATIONDATA
3 
4 /*
5 FrameData:
6     string filename
7     sdlrect frame
8     sdlrect spritesourcesize
9     float duration
10 
11 AnimationData:
12     string name
13     int from
14     int to
15     string direction -> parse to enum {forward, backward, pingpong, pingpongbackward}
16     string repeat -> parse to int, may be null
17     string userdata
18 
19 AnimationsData:
20     vector<framedata> frames
21     vector<animationdata> frameTags
22 
23 */
24 
25 #include <vector>
26 #include <string>
27 #include <unordered_map>
28 #include <filesystem>
29 #include "../Types/Types.hpp"
30 
31 namespace Mochi::Graphics
32 {
33     struct FrameData
34     {
35         std::string Filename; // for debug purposes
36         Rectf Frame;
37         Rectf SpriteSourceSize;
38         float Duration;
39     };
40 
41     enum AnimationDirection
42     {
43         Forward,
44         Backward,
45         Pingpong,
46         BackwardPingPong
47     };
48 
49     struct FrameTag
50     {
51         std::string Name;
52         int From;
53         int To;
54         AnimationDirection Direction;
55         int Repeat;
56         std::string UserData;
57     };
58 
59     struct AnimationsData
60     {
61         std::filesystem::path TexturePath;
62         Vector2f Size;
63         std::vector<FrameData> Frames;
64         std::unordered_map<std::string, FrameTag> Animations;
65     };
66 }
67 
68 #endif
